import{_ as e,o as s,c as n,a1 as i}from"./chunks/framework.BX4nIuL2.js";const h=JSON.parse('{"title":"机器人运动学与动力学建模","description":"","frontmatter":{},"headers":[],"relativePath":"courses/mobile-robot/theory.md","filePath":"courses/mobile-robot/theory.md"}'),t={name:"courses/mobile-robot/theory.md"};function r(o,a,p,l,$,_){return s(),n("div",null,[...a[0]||(a[0]=[i(`<h1 id="机器人运动学与动力学建模" tabindex="-1">机器人运动学与动力学建模 <a class="header-anchor" href="#机器人运动学与动力学建模" aria-label="Permalink to &quot;机器人运动学与动力学建模&quot;">​</a></h1><p>本章节详细阐述现代移动机器人（如双轮差速、麦克纳姆轮）的物理结构抽象与运动控制模型。</p><hr><h2 id="_1-双轮差速底盘-differential-drive" tabindex="-1">1. 双轮差速底盘（Differential Drive） <a class="header-anchor" href="#_1-双轮差速底盘-differential-drive" aria-label="Permalink to &quot;1. 双轮差速底盘（Differential Drive）&quot;">​</a></h2><p>双轮差速底盘是最常见的移动机器人构型之一，依靠两侧主动轮的转速差实现前进、后退和转向。</p><h3 id="_1-1-几何模型与参数定义" tabindex="-1">1.1 几何模型与参数定义 <a class="header-anchor" href="#_1-1-几何模型与参数定义" aria-label="Permalink to &quot;1.1 几何模型与参数定义&quot;">​</a></h3><ul><li>$2L$: 两主动轮轴距 (Wheelbase)</li><li>$R$: 车轮半径 (Wheel Radius)</li><li>$\\omega_L, \\omega_R$: 左、右轮的旋转角速度 (rad/s)</li><li>$v_L, v_R$: 左、右轮相对于地面的切向线速度 ($v = \\omega \\cdot R$)</li><li>$[x, y, \\theta]^T$: 机器人在全局坐标系下的位姿 (Pose)</li></ul><h3 id="_1-2-运动学正解-forward-kinematics" tabindex="-1">1.2 运动学正解 (Forward Kinematics) <a class="header-anchor" href="#_1-2-运动学正解-forward-kinematics" aria-label="Permalink to &quot;1.2 运动学正解 (Forward Kinematics)&quot;">​</a></h3><p>给定左右轮线速度 $v_L, v_R$，求解机器人的整体线速度 $v$ 和绕几何中心旋转的角速度 $\\omega$：</p><p>$$ v = \\frac{v_R + v_L}{2} $$</p><p>$$ \\omega = \\frac{v_R - v_L}{2L} $$</p><p>机器人在全局坐标系下的状态空间方程（里程计积分基础）为：</p><p>$$ \\dot{x} = v \\cos(\\theta) = \\frac{R(\\omega_R + \\omega_L)}{2} \\cos(\\theta) $$</p><p>$$ \\dot{y} = v \\sin(\\theta) = \\frac{R(\\omega_R + \\omega_L)}{2} \\sin(\\theta) $$</p><p>$$ \\dot{\\theta} = \\omega = \\frac{R(\\omega_R - \\omega_L)}{2L} $$</p><hr><h2 id="_2-麦克纳姆轮底盘-mecanum-wheels" tabindex="-1">2. 麦克纳姆轮底盘（Mecanum Wheels） <a class="header-anchor" href="#_2-麦克纳姆轮底盘-mecanum-wheels" aria-label="Permalink to &quot;2. 麦克纳姆轮底盘（Mecanum Wheels）&quot;">​</a></h2><p>麦克纳姆轮底盘采用 4 个外周呈 $45^\\circ$ 倾斜辊子的特殊车轮，可实现<strong>全向平移</strong>（Omnidirectional Movement），即无需改变车体朝向即可在平面内任意方向平移。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>       Front</span></span>
<span class="line"><span>    [ Wheel 1 ]   [ Wheel 2 ]</span></span>
<span class="line"><span>       (+\\)          (+/)</span></span>
<span class="line"><span>          \\         /</span></span>
<span class="line"><span>           \\       /</span></span>
<span class="line"><span>            =======</span></span>
<span class="line"><span>            |     |</span></span>
<span class="line"><span>            =======</span></span>
<span class="line"><span>           /       \\</span></span>
<span class="line"><span>          /         \\</span></span>
<span class="line"><span>       (-\\)          (-/)</span></span>
<span class="line"><span>    [ Wheel 3 ]   [ Wheel 4 ]</span></span>
<span class="line"><span>        Rear</span></span></code></pre></div><h3 id="_2-1-运动学逆解-inverse-kinematics" tabindex="-1">2.1 运动学逆解 (Inverse Kinematics) <a class="header-anchor" href="#_2-1-运动学逆解-inverse-kinematics" aria-label="Permalink to &quot;2.1 运动学逆解 (Inverse Kinematics)&quot;">​</a></h3><p>在控制链中，我们需要根据目标车体速度 $[v_x, v_y, \\omega_z]^T$ 计算 4 个电机的切向线速度：</p><p>$$ v_1 = v_x - v_y - (a + b)\\omega_z $$</p><p>$$ v_2 = v_x + v_y + (a + b)\\omega_z $$</p><p>$$ v_3 = v_x + v_y - (a + b)\\omega_z $$</p><p>$$ v_4 = v_x - v_y + (a + b)\\omega_z $$</p><ul><li>$a$: 几何中心到轮子横向轴线的距离</li><li>$b$: 几何中心到轮子纵向轴线的距离</li></ul><hr><h2 id="_3-实验课-底盘轨迹跟踪-pure-pursuit-纯追踪" tabindex="-1">3. 实验课：底盘轨迹跟踪 (Pure Pursuit 纯追踪) <a class="header-anchor" href="#_3-实验课-底盘轨迹跟踪-pure-pursuit-纯追踪" aria-label="Permalink to &quot;3. 实验课：底盘轨迹跟踪 (Pure Pursuit 纯追踪)&quot;">​</a></h2><p>纯追踪（Pure Pursuit）算法是一种基于几何追踪的经典横向控制算法。其核心是选择小车前方距离为 $L_d$ 的路径点作为目标点 $G(x_g, y_g)$，计算控制舵角或角速度 $\\omega$ 使小车沿着半径为 $R$ 的圆弧驶向目标点。</p><h3 id="_3-1-核心控制律" tabindex="-1">3.1 核心控制律 <a class="header-anchor" href="#_3-1-核心控制律" aria-label="Permalink to &quot;3.1 核心控制律&quot;">​</a></h3><p>假设小车当前位置在坐标原点，航向角为 $0$。目标点在小车局部坐标系下为 $(e_x, e_y)$：</p><p>$$ \\omega = \\frac{2v \\cdot e_y}{L_d^2} $$</p><p>通过动态调整前视距离 $L_d$（如 $L_d = k \\cdot v + L_{d0}$），可以在低速时保持高精度，在高速时保证轨迹平滑。</p><hr><h2 id="_4-划词批注互动区" tabindex="-1">4. 划词批注互动区 <a class="header-anchor" href="#_4-划词批注互动区" aria-label="Permalink to &quot;4. 划词批注互动区&quot;">​</a></h2><p>如果您对本节的公式推导、或麦轮辊子受力分析有任何疑问，请直接<strong>用鼠标划选目标文字</strong>，即可触发 Hypothesis 侧栏或本地批注面板。 请先在主站登录，登录状态会自动同步至此！</p>`,36)])])}const d=e(t,[["render",r]]);export{h as __pageData,d as default};
